Here is concise code for a Discord bot with a slash command to ban a user:

```js
const { Client, ChatInputCommandInteraction, PermissionFlagsBits } = require('discord.js');

const client = new Client({ intents: [] });

client.on('ready', () => {
  console.log('Ready!'); 
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isChatInputCommand()) return;

  if (interaction.commandName === 'ban') {
    if (!interaction.member.permissions.has(PermissionFlagsBits.BanMembers)) {
      return interaction.reply({ content: 'You do not have permission to use this command!', ephemeral: true });
    }

    const user = interaction.options.getUser('user');
    if (!user) {
      return interaction.reply({ content: 'No user provided!', ephemeral: true });
    }

    await interaction.guild.members.ban(user);
    return interaction.reply({ content: `Banned ${user.tag}!`, ephemeral: true });
  }
});

client.login('token');
```

This handles the basic logic for a slash command to ban a user. It checks permissions, gets the user from options, bans them, and replies confirming the ban.

Here is a concise Cypress testing framework that utilizes Docker and screenshot capturing:

```js
// cypress/plugins/index.js
module.exports = (on, config) => {
  require('@cypress/docker-dev')(on, config)
  return config
}

// cypress.config.js
const { defineConfig } = require('cypress')

module.exports = defineConfig({
  e2e: {
    setupNodeEvents(on, config) {
      on('after:spec', (spec, results) => {
        if (results.video) {
          const screenshotFileName = `${spec.name} - ${results.state}`
          cy.screenshot(screenshotFileName)
        }
      })
    },
  },
})

// cypress/Dockerfile
FROM cypress/included:10.3.0
WORKDIR /e2e
COPY . .

// docker-compose.yml
version: '3'
services:
  cypress:
    build:
      context: .
      dockerfile: cypress/Dockerfile
```

This sets up Docker dev dependencies, takes screenshots after each spec run, names them based on the spec, and builds a Docker image specifically for Cypress with its config and dependencies.

